parameters.jsCode:
// Extract email content and prepare for AI analysis
const email = $input.item(0).json;

const emailData = {
  from: email.from.address,
  fromName: email.from.name || '',
  subject: email.subject || '',
  body: email.textPlain || email.html || '',
  receivedDate: email.date,
  // Truncate body to 2000 chars to save on API costs
  bodyPreview: (email.textPlain || email.html || '').substring(0, 2000)
};

// Create prompt for Claude
const classificationPrompt = `Analyze this email and classify it into one of these categories:

1. SALES_INQUIRY - Potential customer asking about products/services
2. SUPPORT_REQUEST - Existing customer needing help
3. PARTNERSHIP - Collaboration or partnership opportunity
4. VENDOR - Supplier or service provider reaching out
5. SPAM_MARKETING - Unsolicited marketing/sales pitch
6. RECRUITING - Job candidate or recruiter
7. PRESS_MEDIA - Media inquiry or press mention
8. OTHER - Doesn't fit other categories

Email Details:
From: ${emailData.fromName} <${emailData.from}>
Subject: ${emailData.subject}

Body:
${emailData.bodyPreview}

Provide your response in this exact JSON format:
{
  "category": "CATEGORY_NAME",
  "confidence": 0.0-1.0,
  "reasoning": "brief explanation",
  "suggestedAction": "what should be done with this email",
  "urgency": "low|medium|high",
  "extractedEntities": {
    "companyName": "if mentioned",
    "productInterest": "if mentioned",
    "budget": "if mentioned"
  }
}`;

return {
  emailData,
  classificationPrompt
};

parameters.bodyParametersJson:
={{ JSON.stringify({
  model: 'claude-3-haiku-20240307',
  max_tokens: 500,
  messages: [{
    role: 'user',
    content: $json.classificationPrompt
  }]
}) }}

parameters.jsCode:
// Parse Claude's response
const claudeResponse = $input.item(0).json;
const emailData = $input.item(0).json.emailData;

// Extract the JSON from Claude's response
const responseText = claudeResponse.content[0].text;
const classificationData = JSON.parse(responseText);

return {
  email: emailData,
  classification: classificationData
};

